mapper.select:
SELECT p.*, s.supplier_name AS supplier FROM purchases p LEFT JOIN suppliers s ON p.supplier_id = s.id
AND s.supplier_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.ordered_at DESC, p.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE purchases
SET supplier_id = #{supplier_id},
    status      = #{status},
    received_at = #{received_at},
    note        = #{note}
WHERE id = #{id}
